# It sets up both a TLS server and a TLS client using a PSK
# (Pre-Shared Key) mechanism for authentication

import socket
import ssl

# SERVER SIDE

# Create a TCP/IP socket
# This creates a socket using IPv4 (AF_INET) and TCP (SOCK_STREAM)
server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)

# Bind the socket to an address ('localhost') and a port (8443)
# This is the address and port the server will listen for connections on
server_socket.bind(('localhost', 8443))

# Listen for incoming connections with a backlog of 1 connection
server_socket.listen(1)

# Define the Pre-Shared Key (PSK) and identity
psk = b'my_secret_key'  # The shared secret key
psk_identity = b'my_identity'  # The identity used by clients to authenticate

# Callback function to provide the PSK based on the client's identity
def psk_callback(identity, context):
    if identity == psk_identity:
        return psk  # If the identity matches, return the PSK
    else:
        return None  # Otherwise, reject the connection by returning None

# Wrap the socket with TLS
# Create an SSL context for TLS server with PSK support
context = ssl.SSLContext(ssl.PROTOCOL_TLS_SERVER)
# Set the cipher suite that supports PSK authentication
context.set_ciphers('TLS_PSK_WITH_NULL_SHA256')
# Set the server-side PSK callback function for authentication
context.set_psk_server_callback(psk_callback)

# Accept an incoming connection from a client
client_socket, address = server_socket.accept()

# Wrap the client socket with the SSL context to establish a secure connection
ssl_client_socket = context.wrap_socket(client_socket, server_side=True)

# Receive data from the client (maximum of 1024 bytes)
data = ssl_client_socket.recv(1024)
print(f'Received: {data.decode()}')  # Print the received message from the client

# Send a response back to the client
ssl_client_socket.sendall(b'Hello, client!')

# Close the TLS-secured client connection
ssl_client_socket.close()

# Close the original server socket
server_socket.close()



# CLIENT SIDE

import socket
import ssl

# Create a TCP/IP socket for the client
sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)

# Define the Pre-Shared Key (PSK) and identity (same as server-side)
psk = b'my_secret_key'
psk_identity = b'my_identity'

# Create an SSL context for TLS client with PSK support
context = ssl.SSLContext(ssl.PROTOCOL_TLS_CLIENT)
# Set the cipher suite that supports PSK authentication
context.set_ciphers('TLS_PSK_WITH_NULL_SHA256')

# Set the client-side PSK callback function to provide the identity and PSK
context.set_psk_client_callback(lambda hint: (psk_identity, psk))

# Define the server address (localhost) and port (8443) to connect to
server_address = ('localhost', 8443)

# Wrap the socket with the SSL context to establish a secure connection
ssl_sock = context.wrap_socket(sock)

# Connect to the server at the specified address
ssl_sock.connect(server_address)

# Send data to the server
ssl_sock.sendall(b'Hello, server!')

# Receive a response from the server (maximum of 1024 bytes)
data = ssl_sock.recv(1024)
print(f'Received: {data.decode()}')  # Print the received message from the server

# Close the TLS-secured connection
ssl_sock.close()
